// src/pages/Payroll/PayrollPage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CreditCard, DollarSign, AlertTriangle, FileText,
  Play, CheckCircle, Download, Plus, RefreshCw,
  TrendingUp, Users, Zap,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { payrollAPI } from '../../api/services';
import { Badge, SkeletonCard, SkeletonTable, Modal, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';

/* ── Dashboard KPI card ── */
function PayKPI({ icon: Icon, label, value, color, sub }) {
  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div className="stat-card-icon" style={{ background: `${color}22` }}>
        <Icon size={20} style={{ color }} />
      </div>
      <div className="stat-card-value">{value ?? '—'}</div>
      <div className="stat-card-label">{label}</div>
      {sub && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 3 }}>{sub}</div>}
    </div>
  );
}

/* ── Payslip viewer ── */
function PayslipModal({ payslip, onClose }) {
  if (!payslip) return null;

  // Look inside the nested Entry and PayrollRun objects!
  const financialData = payslip.Entry || payslip;
  const runData = payslip.PayrollRun || payslip;

  // Safe extractors for both PascalCase (Prisma) and camelCase
  const startDate = runData.PeriodStartDate || runData.payPeriodStart || runData.PaymentDate || payslip.StartDate;
  const endDate = runData.PeriodEndDate || runData.payPeriodEnd || payslip.EndDate;
  const status = payslip.Status || payslip.status || 'Finalized';

  // Earnings
  const baseSalary = financialData.BaseSalary || financialData.baseSalary || financialData.basicSalary || 0;
  const allowances = financialData.TotalAllowances || financialData.totalAllowances || financialData.allowances || 0;
  const overtime = financialData.OvertimePay || financialData.overtimePay || financialData.overtime || 0;
  const grossPay = financialData.TotalEarnings || financialData.totalEarnings || financialData.GrossIncome || financialData.grossPay || 0;

  // Deductions
  const tax = financialData.TaxAmount || financialData.taxAmount || financialData.incomeTax || financialData.tax || 0;
  const socialSecurity = financialData.EmployeeSocialInsurance || financialData.employeeSocialInsurance || financialData.socialSecurity || 0;
  const absence = Math.abs(financialData.AbsenceDeduction || financialData.absenceDeduction || financialData.UnpaidLeaveDeduction || 0);
  const lateness = Math.abs(financialData.LatenessDeduction || financialData.latenessDeduction || 0);
  const unpaidLeave = Math.abs(financialData.UnpaidLeaveDeduction || financialData.unpaidLeaveDeduction || 0);
  const totalDeductions = financialData.TotalDeductions || financialData.totalDeductions || financialData.deductions || 0;

  const netPay = financialData.NetPay || financialData.netPay || 0;

  return (
    <Modal open={!!payslip} onClose={onClose} title="Payslip Details" size="modal-lg">
      <div style={{
        background: 'var(--bg-base)', border: '1px solid var(--border)',
        borderRadius: 'var(--radius-lg)', padding: 24, marginBottom: 16,
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
          <div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 700 }}>Payslip</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              Period: {startDate ? `${new Date(startDate).toLocaleDateString()} – ${new Date(endDate || startDate).toLocaleDateString()}` : '—'}
            </div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <Badge status={status}>{status}</Badge>
          </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          {/* EARNINGS SECTION */}
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--green)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 8 }}>Earnings</div>
            {[
              { label: 'Basic Salary',    value: baseSalary },
              { label: 'Allowances',      value: allowances },
              { label: 'Overtime Pay',    value: overtime },
              { label: 'Gross Pay',       value: grossPay, bold: true },
            ].map(({ label, value, bold }) => value !== undefined && value > 0 && (
              <div key={label} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)', fontWeight: bold ? 700 : 400 }}>
                <span style={{ fontSize: '0.82rem', color: bold ? 'var(--text-primary)' : 'var(--text-secondary)' }}>{label}</span>
                <span style={{ fontSize: '0.82rem', color: bold ? 'var(--green)' : 'var(--text-primary)' }}>
                  {Number(value).toLocaleString('en-US', { style: 'currency', currency: 'EGP' })}
                </span>
              </div>
            ))}
          </div>

          {/* DEDUCTIONS SECTION */}
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--red)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 8 }}>Deductions</div>
            {[
              { label: 'Income Tax',        value: tax },
              { label: 'Social Security',   value: socialSecurity },
              { label: 'Absence Deduction', value: absence }, 
              { label: 'Lateness Penalty',  value: lateness }, 
              { label: 'Unpaid Leave',      value: unpaidLeave }, 
              { label: 'Total Deductions',  value: totalDeductions, bold: true },
            ].map(({ label, value, bold }) => value !== undefined && value > 0 && (
              <div key={label} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)', fontWeight: bold ? 700 : 400 }}>
                <span style={{ fontSize: '0.82rem', color: bold ? 'var(--text-primary)' : 'var(--text-secondary)' }}>{label}</span>
                <span style={{ fontSize: '0.82rem', color: bold ? 'var(--red)' : 'var(--text-primary)' }}>
                  {Number(value).toLocaleString('en-US', { style: 'currency', currency: 'EGP' })}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Net Pay */}
        <div style={{
          marginTop: 16, padding: '14px 16px',
          background: 'var(--gold-glow)', border: '1px solid rgba(240,180,41,0.3)',
          borderRadius: 'var(--radius-md)',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        }}>
          <span style={{ fontFamily: 'var(--font-display)', fontWeight: 600 }}>NET PAY</span>
          <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 700, color: 'var(--gold)' }}>
            {Number(netPay).toLocaleString('en-US', { style: 'currency', currency: 'EGP' })}
          </span>
        </div>
      </div>
    </Modal>
  );
}

/* ── Main Page Component ── */
export default function PayrollPage() {
  const { user }   = useAuth();
  const isPayroll  = ['Payroll','HR','Admin'].includes(user?.role);

  const [tab, setTab]           = useState('dashboard');
  const [dashboard, setDash]    = useState(null);
  const [runs, setRuns]         = useState([]);
  const [myPayslips, setMySlips]= useState([]);
  const [exceptions, setExcept] = useState([]);
  const [selectedSlip, setSlip] = useState(null);
  const [loadDash, setLoadDash] = useState(true);
  const [loadRuns, setLoadRuns] = useState(true);
  const [createRunModal, setCreateRunModal] = useState(false);
  const [saving, setSaving]     = useState(false);

  const [runForm, setRunForm] = useState({ 
    PolicyID: 1, 
    PeriodStartDate: '', 
    PeriodEndDate: '', 
    CutoffDate: '', 
    PaymentDate: '' 
  });

  // ── Bulletproof Extractor for API Responses ──
  const load = useCallback(() => {
    const extract = (res, label) => {
      let payload = res;
      if (payload && payload.data !== undefined) payload = payload.data;
      if (payload && payload.success !== undefined && payload.data !== undefined) payload = payload.data;
      return payload || null;
    };

    if (isPayroll) {
      payrollAPI.getDashboard()
        .then((res) => { setDash(extract(res, 'Dashboard')); setLoadDash(false); })
        .catch(() => setLoadDash(false));

      payrollAPI.listRuns({ limit: 10 })
        .then((res) => { 
          const payload = extract(res, 'Runs');
          setRuns(Array.isArray(payload) ? payload : (payload?.runs || payload?.payrollRuns || [])); 
          setLoadRuns(false); 
        })
        .catch(() => setLoadRuns(false));

      payrollAPI.listExceptions()
        .then((res) => { 
          const payload = extract(res, 'Exceptions');
          setExcept(Array.isArray(payload) ? payload : (payload?.exceptions || [])); 
        })
        .catch(() => {});
    } else {
      setLoadDash(false); setLoadRuns(false);
    }

    payrollAPI.getMyPayslips()
      .then((res) => {
        const payload = extract(res, 'Payslips');
        setMySlips(Array.isArray(payload) ? payload : (payload?.payslips || []));
      })
      .catch(() => {});
  }, [isPayroll]);

  useEffect(() => { load(); }, [load]);

  const handleRunAction = async (runId, action) => {
    try {
      if (action === 'process')  await payrollAPI.processRun(runId, {});
      if (action === 'approve')  await payrollAPI.approveRun(runId, {});
      if (action === 'finalize') await payrollAPI.finalizeRun(runId);
      if (action === 'payslips') await payrollAPI.generatePayslips(runId);

      if (action === 'bankfile') {
        await payrollAPI.generateBankFile(runId, { FileFormat: 'CSV' }); // Fallback body for safety
        toast.success('Bank file generated and downloading...');
        return; 
      }

      toast.success(`Run ${action}d successfully`);
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || err.response?.data?.message || `Failed to ${action}`);
    }
  };

  const handleCreateRun = async () => {
    setSaving(true);
    try {
      const startDateObj = new Date(runForm.PeriodStartDate);
      const payload = {
        PolicyID: Number(runForm.PolicyID) || 1,
        PeriodYear: startDateObj.getFullYear(),
        PeriodMonth: startDateObj.getMonth() + 1,
        PeriodStartDate: new Date(runForm.PeriodStartDate).toISOString(),
        PeriodEndDate: new Date(runForm.PeriodEndDate).toISOString(),
        CutoffDate: new Date(runForm.CutoffDate || runForm.PeriodEndDate).toISOString(),
        PaymentDate: new Date(runForm.PaymentDate || runForm.PeriodEndDate).toISOString(),
      };

      await payrollAPI.createRun(payload);
      toast.success('Payroll run created successfully');
      setCreateRunModal(false);
      setRunForm({ PolicyID: 1, PeriodStartDate: '', PeriodEndDate: '', CutoffDate: '', PaymentDate: '' });
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || err.response?.data?.message || 'Failed to create run');
    } finally { 
      setSaving(false); 
    }
  };

  const handleResolveException = async (id) => {
    try {
      // This payload perfectly matches the Joi validation schema
      const payload = { 
        resolution: 'Resolved',           // Must be lowercase 'r', exact string 'Resolved'
        ResolutionNotes: 'Resolved manually' // Must be PascalCase 'R' and 'N'
      };

      await payrollAPI.resolveException(id, payload);

      toast.success('Exception resolved');
      load();
    } catch (err) { 
      const errorMsg = err.response?.data?.error?.message || err.response?.data?.message || 'Failed to resolve exception';
      toast.error(errorMsg); 
      console.error("Resolve Exception Error:", err.response?.data);
    }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard'  },
    { id: 'myslips',   label: 'My Payslips' },
    ...(isPayroll ? [
      { id: 'runs',       label: 'Payroll Runs' },
      { id: 'exceptions', label: `Exceptions${exceptions.length ? ` (${exceptions.length})` : ''}` },
    ] : []),
  ];

  const fmt = (v) => v != null ? Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP', maximumFractionDigits: 0 }) : '—';

  // Safe extractors for Dashboard KPIs
  const dashTotalPay = dashboard?.TotalNetAmount || dashboard?.totalNetPay || dashboard?.totalPayroll || 0;
  const dashHeadcount = dashboard?.TotalEmployees || dashboard?.totalEmployees || dashboard?.headcount || dashboard?.employeesPaid || 0;
  const dashActiveRuns = dashboard?.ActiveRuns || dashboard?.activeRuns || dashboard?.pendingRuns || 0;
  const dashExceptions = dashboard?.OpenExceptions || dashboard?.openExceptions || exceptions.length || 0;

  // Safe map for Recharts Monthly Summary
  const chartData = (dashboard?.MonthlySummary || dashboard?.monthlySummary || []).map(d => ({
    month: d.Month || d.month,
    netPay: d.NetPay || d.netPay || d.TotalNetAmount,
    grossPay: d.GrossPay || d.grossPay || d.TotalGrossAmount
  }));

  return (
    <>
      <div className="page-header">
        <h1>Payroll</h1>
        <p>Manage payroll runs, view payslips, and track exceptions</p>
      </div>

      <div className="tabs">
        {TABS.map(({ id, label }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>
            {label}
          </button>
        ))}
      </div>

      {/* ── Dashboard ── */}
      {tab === 'dashboard' && (
        <>
          {loadDash ? (
            <div className="grid-4"><SkeletonCard /><SkeletonCard /><SkeletonCard /><SkeletonCard /></div>
          ) : dashboard ? (
            <>
              <div className="grid-4" style={{ marginBottom: 24 }}>
                <PayKPI icon={DollarSign} color="var(--green)"  label="Total Payroll"     value={fmt(dashTotalPay)} sub="This period" />
                <PayKPI icon={Users}      color="var(--blue)"   label="Employees Paid"    value={dashHeadcount} />
                <PayKPI icon={CreditCard} color="var(--gold)"   label="Active Runs"       value={dashActiveRuns} />
                <PayKPI icon={AlertTriangle} color="var(--red)" label="Open Exceptions"   value={dashExceptions} sub="Needs attention" />
              </div>

              {chartData.length > 0 && (
                <div className="card">
                  <div className="card-header"><div className="card-title">Monthly Payroll Trend</div></div>
                  <ResponsiveContainer width="100%" height={220}>
                    <BarChart data={chartData} margin={{ top: 5, right: 5, bottom: 5, left: 5 }}>
                      <XAxis dataKey="month" tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                      <YAxis tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                      <Tooltip contentStyle={{ background: 'var(--bg-elevated)', border: '1px solid var(--border)', borderRadius: 8, fontSize: 12 }} />
                      <Bar dataKey="netPay" fill="var(--gold)" radius={[4,4,0,0]} name="Net Pay" />
                      <Bar dataKey="grossPay" fill="var(--blue-dim)" radius={[4,4,0,0]} name="Gross" />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              )}
            </>
          ) : (
            <div style={{ textAlign: 'center', padding: 60, color: 'var(--text-muted)' }}>
              {isPayroll ? 'No payroll data available' : 'You do not have access to payroll dashboard'}
            </div>
          )}
        </>
      )}

      {/* ── My Payslips ── */}
      {tab === 'myslips' && (
        <>
          {myPayslips.length === 0 ? (
            <div className="card">
              <div style={{ textAlign: 'center', padding: 50, color: 'var(--text-muted)' }}>
                <FileText size={40} style={{ marginBottom: 12, opacity: 0.4 }} />
                <div>No payslips found</div>
              </div>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>Period</th><th>Gross Pay</th><th>Deductions</th><th>Net Pay</th><th>Status</th><th></th></tr>
                </thead>
                <tbody>
                  {myPayslips.map((slip, i) => {
                    const id = slip.PayslipID || slip.id || i;

                    // Grab data from the nested backend objects!
                    const runData = slip.PayrollRun || slip;
                    const financialData = slip.Entry || slip;

                    const start = runData.PeriodStartDate || runData.payPeriodStart || runData.PaymentDate;
                    const gross = financialData.TotalEarnings || financialData.totalEarnings || financialData.grossPay || financialData.gross || 0;
                    const deds = financialData.TotalDeductions || financialData.totalDeductions || financialData.deductions || 0;
                    const net = financialData.NetPay || financialData.netPay || 0;
                    const status = slip.Status || slip.status || 'Finalized';

                    return (
                      <tr key={id}>
                        <td>
                          {start ? new Date(start).toLocaleDateString('en-US',{month:'short',year:'numeric'}) : '—'}
                        </td>
                        <td style={{ color: 'var(--green)', fontWeight: 500 }}>{fmt(gross)}</td>
                        <td style={{ color: 'var(--red)'   }}>{fmt(deds)}</td>
                        <td style={{ color: 'var(--gold)',  fontWeight: 700 }}>{fmt(net)}</td>
                        <td><Badge status={status}>{status}</Badge></td>
                        <td>
                          <button className="btn btn-ghost btn-sm" onClick={() => setSlip(slip)}>
                            <FileText size={13} /> View
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* ── Payroll Runs (HR/Payroll) ── */}
      {tab === 'runs' && isPayroll && (
        <>
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 16 }}>
            <button className="btn btn-primary" onClick={() => setCreateRunModal(true)}>
              <Plus size={16} /> New Run
            </button>
          </div>

          {loadRuns ? <SkeletonTable /> : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>Run ID</th><th>Period</th><th>Status</th><th>Total Net</th><th>Employees</th><th>Actions</th></tr>
                </thead>
                <tbody>
                  {runs.map((run, i) => {
                    const id = run.PayrollRunID || run.id;
                    const status = run.Status || run.status || 'Draft';
                    const start = run.PeriodStartDate || run.payPeriodStart;
                    const end = run.PeriodEndDate || run.payPeriodEnd;
                    const totalPay = run.TotalNetAmount || run.totalNetPay || 0;
                    const headcount = run.TotalEmployees || run.employeeCount || 0;

                    return (
                      <tr key={id || i}>
                        <td style={{ fontFamily: 'var(--font-display)', fontWeight: 600 }}>
                          #{id || i + 1}
                        </td>
                        <td>
                          {start ? `${new Date(start).toLocaleDateString()} – ${new Date(end || start).toLocaleDateString()}` : '—'}
                        </td>
                        <td><Badge status={status}>{status}</Badge></td>
                        <td style={{ fontWeight: 500 }}>{fmt(totalPay)}</td>
                        <td>{headcount}</td>
                        <td>
                          <div style={{ display: 'flex', gap: 6 }}>
                            {/* Process button appears for both Draft and stuck Processing runs */}
                            {(status === 'Draft' || status === 'Processing') && (
                              <button className="btn btn-primary btn-sm" onClick={() => handleRunAction(id, 'process')}>
                                <Play size={12} /> {status === 'Processing' ? 'Re-Process' : 'Process'}
                              </button>
                            )}

                            {/* Approve ONLY appears when the backend sets it to PendingApproval */}
                            {status === 'PendingApproval' && (
                              <button className="btn btn-success btn-sm" onClick={() => handleRunAction(id, 'approve')}>
                                <CheckCircle size={12} /> Approve
                              </button>
                            )}

                            {/* Finalize ONLY appears when Approved */}
                            {status === 'Approved' && (
                              <button className="btn btn-primary btn-sm" onClick={() => handleRunAction(id, 'finalize')}>
                                <Zap size={12} /> Finalize
                              </button>
                            )}

                            {/* Payslips and Bank Files ONLY appear when Finalized */}
                            {status === 'Finalized' && (
                              <>
                                <button className="btn btn-ghost btn-sm" onClick={() => handleRunAction(id, 'payslips')}>
                                  <FileText size={12} /> Generate Payslips
                                </button>
                                <button className="btn btn-ghost btn-sm" onClick={() => handleRunAction(id, 'bankfile')}>
                                  <Download size={12} /> Bank File
                                </button>
                              </>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
              {runs.length === 0 && (
                <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>No payroll runs yet</div>
              )}
            </div>
          )}
        </>
      )}

      {/* ── Exceptions ── */}
      {tab === 'exceptions' && isPayroll && (
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>Employee</th><th>Type</th><th>Description</th><th>Severity</th><th>Status</th><th></th></tr>
            </thead>
            <tbody>
              {/* Filter out resolved exceptions so they instantly vanish */}
              {exceptions
                .filter(ex => {
                  const status = ex.Status || ex.status || 'Open';
                  return status === 'Open'; 
                })
                .map((ex, i) => {
                const id = ex.ExceptionID || ex.id;
                const empName = ex.Employee?.FullName || ex.employeeName || ex.EmployeeName || '—';
                const type = ex.ExceptionType || ex.type || '—';
                const desc = ex.Description || ex.description || ex.message || '—';
                const severity = ex.Severity || ex.severity || 'Medium';
                const status = ex.Status || ex.status || 'Open';

                return (
                  <tr key={id || i}>
                    <td>{empName}</td>
                    <td>{type}</td>
                    <td style={{ maxWidth: 250 }}><span className="truncate">{desc}</span></td>
                    <td>
                      <span style={{ fontSize: '0.78rem', fontWeight: 600, color: severity === 'High' ? 'var(--red)' : 'var(--amber)' }}>
                        {severity}
                      </span>
                    </td>
                    <td><Badge status={status}>{status}</Badge></td>
                    <td>
                      <button className="btn btn-success btn-sm" onClick={() => handleResolveException(id)}>
                        <CheckCircle size={12} /> Resolve
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {exceptions.length === 0 && (
            <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>No open exceptions 🎉</div>
          )}
        </div>
      )}

      {/* ── Create Run Modal ── */}
      <Modal
        open={createRunModal}
        onClose={() => setCreateRunModal(false)}
        title="Create Payroll Run"
        footer={
          <>
            <button className="btn btn-secondary" onClick={() => setCreateRunModal(false)} disabled={saving}>Cancel</button>
            <button className="btn btn-primary" onClick={handleCreateRun} disabled={saving}>
              {saving ? <InlineSpinner /> : 'Create Run'}
            </button>
          </>
        }
      >
        <div className="form-group">
          <label className="form-label required">Policy ID</label>
          <input className="form-input" type="number" min="1" value={runForm.PolicyID} onChange={e => setRunForm(f => ({ ...f, PolicyID: e.target.value }))} />
          <div style={{fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '4px'}}>The active payroll policy ruleset to apply.</div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label className="form-label required">Period Start Date</label>
            <input className="form-input" type="date" value={runForm.PeriodStartDate} onChange={e => setRunForm(f => ({ ...f, PeriodStartDate: e.target.value }))} />
          </div>
          <div className="form-group">
            <label className="form-label required">Period End Date</label>
            <input className="form-input" type="date" value={runForm.PeriodEndDate} onChange={e => setRunForm(f => ({ ...f, PeriodEndDate: e.target.value }))} />
          </div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label className="form-label required">Attendance Cutoff Date</label>
            <input className="form-input" type="date" value={runForm.CutoffDate} onChange={e => setRunForm(f => ({ ...f, CutoffDate: e.target.value }))} />
          </div>
          <div className="form-group">
            <label className="form-label required">Payment Date</label>
            <input className="form-input" type="date" value={runForm.PaymentDate} onChange={e => setRunForm(f => ({ ...f, PaymentDate: e.target.value }))} />
          </div>
        </div>
      </Modal>
    </>
  );
}
